from flask import Flask, request
import face_recognition
import numpy as np

app = Flask(__name__)

# Load training images for known employees
employee_images = [face_recognition.load_image_file("path/to/employee1.jpg"), 
                   face_recognition.load_image_file("path/to/employee2.jpg"), 
                   #... add more as needed
                  ]

# Get the face encoding of each employee we know
known_face_encodings = [face_recognition.face_encodings(img)[0] for img in employee_images]

@app.route('/identify', methods=['POST'])
def identify():
    # Check if post request has file part
    if 'file' not in request.files:
        return "No file provided", 400
    
    file = request.files['file']
    
    try:
        unknown_face = face_recognition.load_image_file(file)
    except Exception as e:
        return str(e), 500
        
    unknown_encoding = face_recognition.face_encodings(unknown_face)[0]
    
    results = []
    for known_encoding in known_face_encodings:
        result = face_recognition.compare_faces([known_encoding], unknown_encoding)
        results.append({"confidence": float(result[0])}) # confidence score
        
    return {"results": results} # probability distribution over all known faces
    
if __name__ == '__main__':
    app.run()